import { Bot } from "lucide-react";
import { memo } from "react";
import { Markdown } from "~/components/chat/Markdown";
import { Avatar, AvatarFallback } from "~/components/ui/avatar";

// Deterministic color palette for agent avatars.
const AGENT_COLORS = [
  { bg: "bg-amber-500/20", text: "text-amber-400", border: "border-amber-500/20", from: "from-amber-500/12", to: "to-amber-500/6" },
  { bg: "bg-cyan-500/20", text: "text-cyan-400", border: "border-cyan-500/20", from: "from-cyan-500/12", to: "to-cyan-500/6" },
  { bg: "bg-rose-500/20", text: "text-rose-400", border: "border-rose-500/20", from: "from-rose-500/12", to: "to-rose-500/6" },
  { bg: "bg-emerald-500/20", text: "text-emerald-400", border: "border-emerald-500/20", from: "from-emerald-500/12", to: "to-emerald-500/6" },
  { bg: "bg-violet-500/20", text: "text-violet-400", border: "border-violet-500/20", from: "from-violet-500/12", to: "to-violet-500/6" },
  { bg: "bg-orange-500/20", text: "text-orange-400", border: "border-orange-500/20", from: "from-orange-500/12", to: "to-orange-500/6" },
];

function hashString(s: string): number {
  let hash = 0;
  for (let i = 0; i < s.length; i++) {
    hash = Math.imul(31, hash) + s.charCodeAt(i);
  }
  return Math.abs(hash);
}

export function getAgentColor(sessionId: string) {
  return AGENT_COLORS[hashString(sessionId) % AGENT_COLORS.length];
}

interface AgentMessageProps {
  senderName: string;
  senderSessionId: string;
  content: string;
}

export const AgentMessage = memo(function AgentMessage({
  senderName,
  senderSessionId,
  content,
}: AgentMessageProps) {
  const color = getAgentColor(senderSessionId);

  return (
    <div className="flex gap-3 max-md:flex-col max-md:gap-1">
      <Avatar className="h-8 w-8 shrink-0 max-md:h-6 max-md:w-6">
        <AvatarFallback className={`${color.bg} ${color.text}`}>
          <Bot className="h-4 w-4 max-md:h-3 max-md:w-3" />
        </AvatarFallback>
      </Avatar>
      <div className="flex-1 max-w-[85%] max-md:max-w-full min-w-0">
        <span className={`text-[10px] font-medium ${color.text} mb-0.5 block`}>
          {senderName}
        </span>
        <div className={`rounded-lg px-4 py-2 bg-gradient-to-br ${color.from} ${color.to} shadow-lg shadow-black/30 border ${color.border}`}>
          <Markdown content={content} />
        </div>
      </div>
    </div>
  );
});

