import { create } from "zustand";
import type { TeamInfo, TeamMember, TimelineEvent } from "~/lib/team-actions";

interface TeamState {
  teams: Record<string, TeamInfo>;
  timelines: Record<string, TimelineEvent[]>;

  setTeams: (teams: TeamInfo[]) => void;
  addTeam: (team: TeamInfo) => void;
  removeTeam: (teamId: string) => void;
  updateTeamName: (teamId: string, name: string) => void;

  addMember: (teamId: string, member: TeamMember) => void;
  removeMember: (teamId: string, sessionId: string) => void;

  setTimeline: (teamId: string, events: TimelineEvent[]) => void;
  appendTimelineEvent: (teamId: string, event: TimelineEvent) => void;

  getTeamForSession: (sessionId: string) => TeamInfo | undefined;
}

export const useTeamStore = create<TeamState>((set, get) => ({
  teams: {},
  timelines: {},

  setTeams: (teams) =>
    set({
      teams: Object.fromEntries(teams.map((t) => [t.id, t])),
    }),

  addTeam: (team) =>
    set((s) => ({
      teams: { ...s.teams, [team.id]: team },
    })),

  removeTeam: (teamId) =>
    set((s) => {
      const { [teamId]: _, ...rest } = s.teams;
      const { [teamId]: __, ...restTimelines } = s.timelines;
      return { teams: rest, timelines: restTimelines };
    }),

  updateTeamName: (teamId, name) =>
    set((s) => {
      const team = s.teams[teamId];
      if (!team) return s;
      return { teams: { ...s.teams, [teamId]: { ...team, name } } };
    }),

  addMember: (teamId, member) =>
    set((s) => {
      const team = s.teams[teamId];
      if (!team) return s;
      if (team.members.some((m) => m.sessionId === member.sessionId)) return s;
      return {
        teams: { ...s.teams, [teamId]: { ...team, members: [...team.members, member] } },
      };
    }),

  removeMember: (teamId, sessionId) =>
    set((s) => {
      const team = s.teams[teamId];
      if (!team) return s;
      return {
        teams: {
          ...s.teams,
          [teamId]: { ...team, members: team.members.filter((m) => m.sessionId !== sessionId) },
        },
      };
    }),

  setTimeline: (teamId, events) =>
    set((s) => ({
      timelines: { ...s.timelines, [teamId]: events },
    })),

  appendTimelineEvent: (teamId, event) =>
    set((s) => ({
      timelines: {
        ...s.timelines,
        [teamId]: [...(s.timelines[teamId] ?? []), event],
      },
    })),

  getTeamForSession: (sessionId) => {
    const teams = get().teams;
    return Object.values(teams).find((t) => t.members.some((m) => m.sessionId === sessionId));
  },
}));

import { Send, Users } from "lucide-react";
import { memo, useCallback, useEffect, useRef, useState } from "react";
import { toast } from "sonner";
import { getAgentColor } from "~/components/chat/AgentMessage";
import { Markdown } from "~/components/chat/Markdown";
import { Avatar, AvatarFallback } from "~/components/ui/avatar";
import { Button } from "~/components/ui/button";
import { useWebSocket } from "~/hooks/useWebSocket";
import { getTeamTimeline, sendTeamMessage } from "~/lib/team-actions";
import { cn, getErrorMessage } from "~/lib/utils";
import type { SessionMetadata } from "~/stores/chat-store";
import { useTeamStore } from "~/stores/team-store";

interface TeamViewProps {
  sessionId: string;
  teamId: string;
  sessions: Record<string, { meta: SessionMetadata }>;
}

export const TeamView = memo(function TeamView({ sessionId, teamId, sessions }: TeamViewProps) {
  const ws = useWebSocket();
  const team = useTeamStore((s) => s.teams[teamId]);
  const timeline = useTeamStore((s) => s.timelines[teamId] ?? []);
  const [targetId, setTargetId] = useState<string>("");
  const [message, setMessage] = useState("");
  const [sending, setSending] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Load timeline on mount
  useEffect(() => {
    getTeamTimeline(ws, teamId)
      .then((events) => useTeamStore.getState().setTimeline(teamId, events))
      .catch(() => {});
  }, [ws, teamId]);

  // Auto-scroll on new events
  useEffect(() => {
    scrollRef.current?.scrollTo({ top: scrollRef.current.scrollHeight, behavior: "smooth" });
  }, [timeline.length]);

  const handleSend = useCallback(async () => {
    if (!message.trim() || !targetId) return;
    setSending(true);
    try {
      await sendTeamMessage(ws, sessionId, targetId, message.trim());
      setMessage("");
    } catch (err) {
      toast.error(getErrorMessage(err, "Failed to send message"));
    } finally {
      setSending(false);
    }
  }, [ws, sessionId, targetId, message]);

  if (!team) return null;

  const otherMembers = team.members.filter((m) => m.sessionId !== sessionId);

  return (
    <div className="flex flex-col h-full">
      {/* Member list */}
      <div className="shrink-0 border-b px-3 py-2">
        <div className="flex items-center gap-1.5 text-xs text-muted-foreground mb-1.5">
          <Users className="h-3 w-3" />
          <span className="font-medium">{team.name || "Team"}</span>
          <span>({team.members.length})</span>
        </div>
        <div className="flex flex-col gap-1">
          {team.members.map((member) => {
            const color = getAgentColor(member.sessionId);
            const isSelf = member.sessionId === sessionId;
            const sessionData = sessions[member.sessionId];
            const state = sessionData?.meta.state ?? member.state;
            return (
              <div
                key={member.sessionId}
                className="flex items-center gap-2 text-xs px-1 py-0.5 rounded"
              >
                <div className={cn("h-2 w-2 rounded-full shrink-0", color.bg)} />
                <span className={cn("truncate", isSelf && "font-medium")}>
                  {member.name || "Unnamed"}
                  {isSelf && " (you)"}
                </span>
                {member.role && (
                  <span className="text-muted-foreground truncate">{member.role}</span>
                )}
                <span
                  className={cn(
                    "ml-auto text-[10px] capitalize shrink-0",
                    state === "running" ? "text-primary" : "text-muted-foreground",
                  )}
                >
                  {state}
                </span>
              </div>
            );
          })}
        </div>
      </div>

      {/* Timeline */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto px-3 py-2 space-y-2">
        {timeline.length === 0 && (
          <p className="text-xs text-muted-foreground text-center py-4">No messages yet</p>
        )}
        {timeline.map((event, i) => {
          const color = getAgentColor(event.senderSessionId);
          const isSelf = event.senderSessionId === sessionId;
          return (
            <div key={i} className={cn("flex gap-2", isSelf && "flex-row-reverse")}>
              <Avatar className="h-5 w-5 shrink-0">
                <AvatarFallback
                  className={cn("text-[10px] font-bold", color.bg, color.text)}
                >
                  {(event.senderName || "?")[0]?.toUpperCase()}
                </AvatarFallback>
              </Avatar>
              <div className={cn("max-w-[80%]", isSelf && "text-right")}>
                <span className={cn("text-[10px] block mb-0.5", color.text)}>
                  {event.senderName}
                </span>
                <div
                  className={cn(
                    "rounded-lg px-3 py-1.5 text-xs border",
                    `bg-gradient-to-br ${color.from} ${color.to} ${color.border}`,
                  )}
                >
                  <Markdown content={event.content} />
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Composer */}
      <div className="shrink-0 border-t px-3 py-2 space-y-1.5">
        <select
          value={targetId}
          onChange={(e) => setTargetId(e.target.value)}
          className="w-full text-xs bg-background border rounded px-2 py-1"
        >
          <option value="">Send to...</option>
          {otherMembers.map((m) => (
            <option key={m.sessionId} value={m.sessionId}>
              {m.name || "Unnamed"}
              {m.role && ` (${m.role})`}
            </option>
          ))}
        </select>
        <div className="flex gap-1.5">
          <input
            value={message}
            onChange={(e) => setMessage(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Enter" && !e.shiftKey) {
                e.preventDefault();
                handleSend();
              }
            }}
            placeholder="Message..."
            className="flex-1 text-xs bg-background border rounded px-2 py-1.5 outline-none focus:ring-1 focus:ring-ring"
          />
          <Button
            size="sm"
            variant="ghost"
            className="h-7 px-2"
            disabled={!message.trim() || !targetId || sending}
            onClick={handleSend}
          >
            <Send className="h-3.5 w-3.5" />
          </Button>
        </div>
      </div>
    </div>
  );
});

